/* Haydar Pack V33 Stage 5 split file: 01-core.js. Preserves execution order from stable version. */
// ================= DATA / HELPERS =================
var STATUSES = ['تحت التنفيذ','تم الشحن','تم التوصيل للعميل'];
var STATUS_CLASS = {'تحت التنفيذ':'bg-amber','تم الشحن':'bg-purple','تم التوصيل للعميل':'bg-green'};
var DB = {clients:[],factories:[],orders:[],payments:[],transfers:[],expenses:[],settings:{autoSync:false,googleClientId:''},_id:1,version:4};
var selStatus='all', selFac='all', selPeriod='all', homePeriod='month', selMonth=curMonth(), repPeriod='month', selRepMonth=curMonth();
var activePage='home';
var lastReceiptPreview = {};
var tokenClient=null, accessToken='', driveFileId='', syncTimer=null;
var DRIVE_SCOPE='https://www.googleapis.com/auth/drive.appdata';
var DRIVE_FILE='hayder_bags_data.json';
function uid(){ DB._id=(DB._id||1)+1; return 'i'+DB._id }
function g(id){ return document.getElementById(id) }
function safe(v){ return String(v??'').replace(/[&<>"']/g,function(m){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]}) }
function num(v){ var n=parseFloat(v); return isNaN(n)?0:n }
function localDateStr(d){ d=d||new Date(); var y=d.getFullYear(),m=String(d.getMonth()+1).padStart(2,'0'),day=String(d.getDate()).padStart(2,'0'); return y+'-'+m+'-'+day; }
function todayStr(){ return localDateStr(new Date()); }
function curMonth(){ return todayStr().slice(0,7); }
function fmt(n){ var v=num(n); var hasFrac=Math.abs(v%1)>0.0000001; return v.toLocaleString('ar-EG',{minimumFractionDigits:hasFrac?2:0,maximumFractionDigits:2})+' ج' }
function countFmt(n){ return Math.round(num(n)).toLocaleString('ar-EG') }
function monthLabel(m){ var names=['يناير','فبراير','مارس','أبريل','مايو','يونيو','يوليو','أغسطس','سبتمبر','أكتوبر','نوفمبر','ديسمبر']; var p=m.split('-'); return names[parseInt(p[1],10)-1]+' '+p[0] }
function dateOf(v){ if(!v) return null; var d=new Date(v+'T00:00:00'); return isNaN(d)?null:d }
function isThisWeek(v){ var d=dateOf(v); if(!d) return false; var now=new Date(); var start=new Date(now); var day=(start.getDay()+6)%7; start.setDate(start.getDate()-day); start.setHours(0,0,0,0); var end=new Date(start); end.setDate(end.getDate()+7); return d>=start && d<end }
function dateMatches(v,period,month){ if(period==='all') return true; if(period==='today') return v===todayStr(); if(period==='week') return isThisWeek(v); if(period==='month') return (v||'').startsWith(month||curMonth()); return true }
function statusBadge(st){ return '<span class="badge '+(STATUS_CLASS[st]||'bg-gray')+'">'+safe(st||'تحت التنفيذ')+'</span>' }
function toast(msg){ var t=g('toast'); t.textContent=msg; t.classList.add('show'); setTimeout(function(){ t.classList.remove('show') },2200) }
function setSyncState(state,msg){ var d=g('sync-dot'); if(d){ d.className='sync-dot '+(state||'') } var s=g('sync-status'); if(s) s.textContent=msg||'' }

function normalizeStatus(st){
  if(st==='تم التوصيل للعميل') return 'تم التوصيل للعميل';
  if(st==='تم الانتهاء') return 'تم الشحن';
  return STATUSES.includes(st) ? st : 'تحت التنفيذ';
}
function migrate(){
  DB.settings=DB.settings||{autoSync:false,googleClientId:'',lastSeenMonth:curMonth(),extraMonths:[]};
  if(!DB.settings.lastSeenMonth) DB.settings.lastSeenMonth=curMonth(); if(!DB.settings.extraMonths) DB.settings.extraMonths=[];
  DB.clients=DB.clients||[]; DB.factories=DB.factories||[]; DB.orders=DB.orders||[]; DB.payments=DB.payments||[]; DB.transfers=DB.transfers||[]; DB.expenses=DB.expenses||[];
  DB.orders.forEach(function(o){
    o.status=normalizeStatus(o.status);
    if(o.qty==null && o.fQty!=null) o.qty=o.fQty;
    if(o.fQty==null) o.fQty=0;
    if(o.fPrice==null) o.fPrice=0;
    if(o.fAk==null) o.fAk=0;
    if(o.deposit==null) o.deposit=0;
    if(!o.name) o.name='';
  });
  if(!DB.factories.length){ DB.factories=[{id:uid(),name:'شريف',phone:'',debt:0},{id:uid(),name:'كوركت بلاست',phone:'',debt:0},{id:uid(),name:'القناطر',phone:'',debt:0}]; }
}
function autoRefreshCurrentMonth(){
  var cm=curMonth();
  if(!DB.settings) DB.settings={};
  if(DB.settings.lastSeenMonth!==cm){
    DB.settings.lastSeenMonth=cm;
    selMonth=cm; selRepMonth=cm;
    save(true); refreshAll();
    toast('تم إضافة شهر '+monthLabel(cm)+' تلقائياً');
  }
}
function save(skipSync){ try{localStorage.setItem('hayder_bags_app',JSON.stringify(DB))}catch(e){toast('تعذر حفظ البيانات محلياً')} if(!skipSync) scheduleSync(); }
function load(){ try{ var d=localStorage.getItem('hayder_bags_app'); if(d) DB=JSON.parse(d); }catch(e){} migrate(); save(true); refreshAll(); }
function refreshAll(){ renderHome(); renderOrders(); renderClients(); renderFactories(); renderReports(); }

// ================= NAV / DRAWERS =================
function showPage(name,btn){ activePage=name; document.querySelectorAll('.page').forEach(function(p){p.classList.remove('active')}); document.querySelectorAll('.nb').forEach(function(b){b.classList.remove('active')}); g('pg-'+name).classList.add('active'); btn.classList.add('active'); if(name==='home')renderHome(); if(name==='orders')renderOrders(); if(name==='clients')renderClients(); if(name==='factories')renderFactories(); if(name==='reports')renderReports(); }
function openDrawer(id){ var el=g(id); el.classList.add('open'); el.querySelectorAll('input[type=date]').forEach(function(i){ if(!i.value) i.value=todayStr() }); }
function closeDrawer(id){ g(id).classList.remove('open') }
document.addEventListener('click',function(e){ if(e.target.classList.contains('overlay')) e.target.classList.remove('open'); });
function fillSelect(id,arr,placeholder){ g(id).innerHTML='<option value="">'+placeholder+'</option>'+arr.map(function(x){return '<option value="'+safe(x.id)+'">'+safe(x.name)+'</option>'}).join('') }
function fillOrderSelects(){ fillSelect('o-client',DB.clients,'— اختر عميل —'); fillSelect('o-factory',DB.factories,'— اختر مصنع —'); g('o-status').innerHTML=STATUSES.map(function(s){return '<option>'+s+'</option>'}).join(''); }
function fillTransferSelect(){ fillSelect('t-fac',DB.factories,'— اختر مصنع —') }

// ================= CALC =================
function billQty(o){ return num(o.fQty)>0 ? num(o.fQty) : num(o.qty) }
function clientTotalForOrder(o){ return billQty(o)*num(o.price)+num(o.aklashe) }
function factoryTotalForOrder(o){ return num(o.fQty)*num(o.fPrice)+num(o.fAk) }
function profitForOrder(o){ return clientTotalForOrder(o)-factoryTotalForOrder(o) }
function clientTotal(cid){ return DB.orders.filter(function(o){return o.clientId===cid}).reduce(function(s,o){return s+clientTotalForOrder(o)},0) }
function clientDeposits(cid){ return DB.orders.filter(function(o){return o.clientId===cid}).reduce(function(s,o){return s+num(o.deposit)},0) }
function clientPaid(cid){ return DB.payments.filter(function(p){return p.clientId===cid}).reduce(function(s,p){return s+num(p.amount)},0)+clientDeposits(cid) }
function clientBalance(cid){ var c=DB.clients.find(function(x){return x.id===cid}); return clientTotal(cid)+(c?num(c.debt):0)-clientPaid(cid) }
function factoryOrders(fid){ return DB.orders.filter(function(o){return o.factoryId===fid}) }
function factoryTotal(fid){ return factoryOrders(fid).reduce(function(s,o){return s+factoryTotalForOrder(o)},0) }
function factoryPaid(fid){ return DB.transfers.filter(function(t){return t.factoryId===fid}).reduce(function(s,t){return s+num(t.amount)},0) }
function factoryBalance(fid){ var f=DB.factories.find(function(x){return x.id===fid}); return factoryTotal(fid)+(f?num(f.debt):0)-factoryPaid(fid) }
function periodOrders(period,month){ return DB.orders.filter(function(o){return dateMatches(o.date,period,month)}) }
function periodExpenses(period,month){ return DB.expenses.filter(function(e){return dateMatches(e.date,period,month)}) }
function periodTotals(period,month){ var ords=periodOrders(period,month); var income=ords.reduce(function(s,o){return s+clientTotalForOrder(o)},0); var fcost=ords.reduce(function(s,o){return s+factoryTotalForOrder(o)},0); var exp=periodExpenses(period,month).reduce(function(s,e){return s+num(e.amount)},0); return {orders:ords,income:income,fcost:fcost,expenses:exp,profit:income-fcost-exp}; }
function calcOTotal(){ var q=num(g('o-qty').value), p=num(g('o-price').value), a=num(g('o-ak').value), d=num(g('o-deposit')?g('o-deposit').value:0); var total=q*p+a; g('o-total-prev').textContent=fmt(total); if(g('o-due-prev')) g('o-due-prev').textContent=fmt(Math.max(0,total-d)); }
function calcFPTotal(){ var q=num(g('fp-qty').value), p=num(g('fp-price').value), a=num(g('fp-ak').value); g('fp-total-prev').textContent=fmt(q*p+a); var oid=g('fp-oid').value; var o=DB.orders.find(function(x){return x.id===oid}); if(o){ g('fp-client-total-prev').textContent=fmt(q*num(o.price)+num(o.aklashe)); } }

// ================= ORDER NUMBER / FORMS =================
function nextOrderCode(dateValue){ var month=String(dateValue||todayStr()).slice(0,7); if(!/^\d{4}-\d{2}$/.test(month)) month=curMonth(); var ym=month.replace('-',''), max=0; DB.orders.forEach(function(o){ var m=String(o.code||'').match(new RegExp('^ORD-'+ym+'-(\\d+)$')); if(m) max=Math.max(max,parseInt(m[1],10)); }); return 'ORD-'+ym+'-'+String(max+1).padStart(4,'0'); }
function updateOrderCodeForDate(){ var edit=g('o-edit-id'), code=g('o-code'), date=g('o-date'); if(code&&date&&(!edit||!edit.value)) code.value=nextOrderCode(date.value||todayStr()); }
function openOrderForm(id){ if(g('dr-order-detail')) closeDrawer('dr-order-detail'); fillOrderSelects(); ['o-name','o-handle','o-print','o-size','o-notes'].forEach(function(x){g(x).value=''}) ; if(g('o-color')) g('o-color').value='ابيض'; ['o-qty','o-price','o-ak','o-deposit'].forEach(function(x){g(x).value=''}); g('o-client').value=''; g('o-factory').value=''; g('o-status').value='تحت التنفيذ'; g('o-date').value=todayStr(); g('o-edit-id').value=''; g('o-code').value=nextOrderCode(g('o-date').value); g('order-drawer-title').textContent='أوردر جديد';
  if(id){ var o=DB.orders.find(function(x){return x.id===id}); if(o){ g('o-edit-id').value=o.id; g('o-code').value=o.code||''; g('o-date').value=o.date||todayStr(); g('o-name').value=o.name||''; g('o-client').value=o.clientId||''; g('o-factory').value=o.factoryId||''; g('o-status').value=o.status||'تحت التنفيذ'; g('o-type').value=o.type||'يد داخلية'; g('o-color').value=o.color||''; g('o-handle').value=o.handle||''; g('o-print').value=o.print||''; g('o-size').value=o.size||''; g('o-qty').value=o.qty||''; g('o-price').value=o.price||''; g('o-ak').value=o.aklashe||''; g('o-deposit').value=o.deposit||''; g('o-notes').value=o.notes||''; g('order-drawer-title').textContent='تعديل الأوردر'; }} calcOTotal(); openDrawer('dr-order'); }
function saveOrder(){ var cid=g('o-client').value, fid=g('o-factory').value; if(!cid){toast('اختر العميل');return} if(!fid){toast('اختر المصنع');return} var id=g('o-edit-id').value; var patch={ code:g('o-code').value||nextOrderCode(), name:g('o-name').value.trim(), clientId:cid, factoryId:fid, status:g('o-status').value, type:g('o-type').value, color:g('o-color').value, handle:g('o-handle').value, print:g('o-print').value, size:g('o-size').value, qty:num(g('o-qty').value), price:num(g('o-price').value), aklashe:num(g('o-ak').value), deposit:num(g('o-deposit')?g('o-deposit').value:0), date:g('o-date').value||todayStr(), notes:g('o-notes').value };
  if(patch.status==='تم التوصيل للعميل') patch.deliveredAt=patch.deliveredAt||todayStr();
  if(id){ var o=DB.orders.find(function(x){return x.id===id}); Object.assign(o,patch); toast('تم تعديل الأوردر'); }
  else { DB.orders.push(Object.assign({id:uid(),fQty:0,fPrice:0,fAk:0},patch)); toast('تم حفظ الأوردر'); }
  save(); closeDrawer('dr-order'); refreshAll(); }
function deleteOrder(id){
  var o=DB.orders.find(function(x){return x.id===id}); if(!o)return;
  if(!confirm('تأكيد حذف الأوردر '+(o.code||'')+' نهائياً من البيانات؟'))return;
  var linked=(DB.expenses||[]).filter(function(e){return e.orderId===id});
  if(linked.length){
    var choice=prompt('يوجد '+linked.length+' مصروف مرتبط بالأوردر.\nاكتب 1 لتحويلها إلى مصروفات عامة.\nاكتب 2 لحذفها مع الأوردر.\nاكتب 0 لإلغاء العملية.','1');
    if(choice!=='1'&&choice!=='2')return;
    if(choice==='1') linked.forEach(function(e){e.orderId=''; e.note=(e.note?e.note+' · ':'')+'تم تحويله لمصروف عام بعد حذف '+(o.code||'الأوردر');});
    else DB.expenses=DB.expenses.filter(function(e){return e.orderId!==id});
  }
  DB.orders=DB.orders.filter(function(x){return x.id!==id});
  save(); closeDrawer('dr-order-detail'); refreshAll(); toast('تم حذف الأوردر نهائياً');
}
function changeOrderStatus(id,st){ var o=DB.orders.find(function(x){return x.id===id}); if(!o)return; o.status=st; if(st==='تم التوصيل للعميل') o.deliveredAt=todayStr(); save(); renderOrders(); renderHome(); if(g('order-detail-body')) openOrderDetail(id); }

// ================= SAVE ENTITIES =================
function saveClient(){ var name=g('c-name').value.trim(); if(!name){toast('أدخل اسم العميل');return} DB.clients.push({id:uid(),name:name,phone:g('c-phone').value,addr:g('c-addr').value,debt:num(g('c-debt').value),month:curMonth()}); save(); ['c-name','c-phone','c-addr','c-debt'].forEach(function(id){g(id).value=''}); closeDrawer('dr-client'); toast('تم إضافة العميل'); refreshAll(); }
function openFactoryForm(id){ ['f-name','f-phone','f-debt'].forEach(function(x){g(x).value=''}); g('f-edit-id').value=''; g('factory-drawer-title').textContent='مصنع جديد'; if(id){ var f=DB.factories.find(function(x){return x.id===id}); if(f){ g('f-edit-id').value=f.id; g('f-name').value=f.name||''; g('f-phone').value=f.phone||''; g('f-debt').value=num(f.debt)||''; g('factory-drawer-title').textContent='تعديل بيانات المصنع'; }} openDrawer('dr-factory'); }
function saveFactory(){ var name=g('f-name').value.trim(); if(!name){toast('أدخل اسم المصنع');return} var id=g('f-edit-id').value, isEdit=!!id; if(isEdit){ var f=DB.factories.find(function(x){return x.id===id}); if(!f)return; f.name=name; f.phone=g('f-phone').value; f.debt=num(g('f-debt').value); } else { DB.factories.push({id:uid(),name:name,phone:g('f-phone').value,debt:num(g('f-debt').value)}); } save(); ['f-name','f-phone','f-debt'].forEach(function(x){g(x).value=''}); g('f-edit-id').value=''; closeDrawer('dr-factory'); refreshAll(); toast(isEdit?'تم تعديل بيانات المصنع':'تم إضافة المصنع'); }
function deleteFactory(id){ var f=DB.factories.find(function(x){return x.id===id}); if(!f)return; var linkedOrders=DB.orders.filter(function(o){return o.factoryId===id}).length; var linkedTransfers=DB.transfers.filter(function(t){return t.factoryId===id}).length; if(linkedOrders||linkedTransfers){ toast('لا يمكن حذف مصنع عليه أوردرات أو تحويلات. انقل أو احذف البيانات المرتبطة أولاً.'); return; } if(confirm('تأكيد حذف مصنع '+f.name+'؟')){ DB.factories=DB.factories.filter(function(x){return x.id!==id}); save(); toast('تم حذف المصنع'); refreshAll(); } }
function openTransferForm(fid){ fillTransferSelect(); g('t-fac').value=fid||''; ['t-amt','t-note'].forEach(function(id){g(id).value=''}); g('t-date').value=todayStr(); g('t-receipt').value=''; g('t-receipt-preview').classList.add('hide'); lastReceiptPreview.transfer=null; openDrawer('dr-transfer'); }
function saveTransfer(){ var fid=g('t-fac').value, amt=num(g('t-amt').value); if(!fid){toast('اختر المصنع');return} if(!amt){toast('أدخل المبلغ');return} DB.transfers.push({id:uid(),factoryId:fid,amount:amt,type:g('t-type').value,date:g('t-date').value||todayStr(),note:g('t-note').value,receipt:lastReceiptPreview.transfer||null}); save(); closeDrawer('dr-transfer'); toast('تم حفظ التحويل'); refreshAll(); }
function saveExpense(){ var amt=num(g('ex-amt').value); if(!amt){toast('أدخل المبلغ');return} DB.expenses.push({id:uid(),type:g('ex-type').value,amount:amt,date:g('ex-date').value||todayStr(),note:g('ex-note').value}); save(); ['ex-amt','ex-note'].forEach(function(id){g(id).value=''}); closeDrawer('dr-expense'); toast('تم حفظ المصروف'); refreshAll(); }
function savePayment(){ var amt=num(g('pay-amt').value), cid=g('pay-cid').value; if(!amt){toast('أدخل المبلغ');return} DB.payments.push({id:uid(),clientId:cid,amount:amt,date:g('pay-date').value||todayStr(),note:g('pay-note').value,receipt:lastReceiptPreview.payment||null}); save(); closeDrawer('dr-payment'); toast('تم حفظ الدفعة'); refreshAll(); setTimeout(function(){openClientDetail(cid)},250); }
function previewReceipt(input,imgId){ var file=input.files&&input.files[0]; if(!file)return; if(file.size>1200*1024){ toast('حجم الصورة كبير. يفضل أقل من 1.2MB'); }
  var reader=new FileReader(); reader.onload=function(e){ var data=e.target.result; var obj={name:file.name,type:file.type,size:file.size,data:data}; if(imgId.indexOf('pay')===0) lastReceiptPreview.payment=obj; else lastReceiptPreview.transfer=obj; var img=g(imgId); img.src=data; img.classList.remove('hide'); }; reader.readAsDataURL(file); }
function openPaymentForm(cid){ var c=DB.clients.find(function(x){return x.id===cid}); g('pay-cid').value=cid; g('pay-info').textContent='تسجيل دفعة لـ: '+(c?c.name:''); ['pay-amt','pay-note'].forEach(function(id){g(id).value=''}); g('pay-date').value=todayStr(); g('pay-receipt').value=''; g('pay-receipt-preview').classList.add('hide'); lastReceiptPreview.payment=null; openDrawer('dr-payment'); }
function saveFactoryPrices(){ var oid=g('fp-oid').value; var o=DB.orders.find(function(x){return x.id===oid}); if(!o)return; o.fQty=num(g('fp-qty').value); o.fPrice=num(g('fp-price').value); o.fAk=num(g('fp-ak').value); save(); closeDrawer('dr-fprice'); toast('تم حفظ بيانات المصنع والعدد النهائي'); refreshAll(); }
function openFactoryPrices(id){ if(g('dr-order-detail')) closeDrawer('dr-order-detail'); var o=DB.orders.find(function(x){return x.id===id}); if(!o)return; var c=DB.clients.find(function(x){return x.id===o.clientId})||{name:'؟'}; g('fp-oid').value=o.id; g('fp-info').textContent=o.code+' · '+c.name+' · العدد المبدئي '+countFmt(o.qty); g('fp-qty').value=num(o.fQty)||num(o.qty)||''; g('fp-price').value=num(o.fPrice)||''; g('fp-ak').value=num(o.fAk)||''; calcFPTotal(); openDrawer('dr-fprice'); }

// ================= RENDERING =================
function periodChips(container,current,fn){ var opts=[['all','كل البيانات'],['today','اليوم'],['week','الأسبوع الحالي'],['month','الشهر الحالي']]; g(container).innerHTML=opts.map(function(o){return '<button class="chip '+(current===o[0]?'active':'')+'" onclick="'+fn+'(\''+o[0]+'\')">'+o[1]+'</button>'}).join(''); }
function setHomePeriod(p){ homePeriod=p; renderHome(); }
function setRepPeriod(p){ repPeriod=p; renderReports(); }
function monthAdd(m,delta){ var p=String(m||curMonth()).split('-'), y=parseInt(p[0],10), mo=parseInt(p[1],10)-1+(delta||0); if(!isFinite(y)||!isFinite(mo)) return curMonth(); y+=Math.floor(mo/12); mo=((mo%12)+12)%12; return y+'-'+String(mo+1).padStart(2,'0'); }
function monthCompare(a,b){ return String(a).localeCompare(String(b)); }
function allAvailableMonths(){
  var start='2026-06';
  var end=monthCompare(curMonth(),'2026-12')>0?curMonth():'2026-12';
  DB.settings=DB.settings||{}; DB.settings.extraMonths=DB.settings.extraMonths||[];
  DB.settings.extraMonths.forEach(function(m){ if(monthCompare(m,end)>0) end=m; });
  [DB.orders,DB.expenses,DB.payments,DB.transfers].forEach(function(arr){ (arr||[]).forEach(function(x){ var m=String(x.date||'').slice(0,7); if(/^\d{4}-\d{2}$/.test(m) && monthCompare(m,end)>0) end=m; }); });
  var months=[]; var m=start;
  while(monthCompare(m,end)<=0){ months.push(m); m=monthAdd(m,1); if(months.length>84)break; }
  return months;
}
function addNextMonth(){ DB.settings=DB.settings||{}; DB.settings.extraMonths=DB.settings.extraMonths||[]; var months=allAvailableMonths(); var next=monthAdd(months[months.length-1]||curMonth(),1); if(!DB.settings.extraMonths.includes(next)) DB.settings.extraMonths.push(next); selRepMonth=next; selMonth=next; repPeriod='month'; homePeriod='month'; save(); renderReports(); renderHome(); toast('تم إضافة شهر '+monthLabel(next)); }
function buildMonthTabs(container,current,cbName){
  var el=g(container); var months=allAvailableMonths();
  if(months.indexOf(current)<0) current=curMonth();
  el.innerHTML=months.map(function(m){ return '<button class="mt-btn '+(m===current?'active':'')+'" onclick="'+cbName+'(\''+m+'\')">'+monthLabel(m)+(m===curMonth()?' ⭐':'')+'</button>' }).join('');
}
function selectHomeMonth(m){ selMonth=m; homePeriod='month'; renderHome(); }
function selectRepMonth(m){ selRepMonth=m; repPeriod='month'; renderReports(); }

function renderHome(){ periodChips('home-periods',homePeriod,'setHomePeriod'); buildMonthTabs('home-months',selMonth,'selectHomeMonth'); var t=periodTotals(homePeriod,selMonth); g('h-income').textContent=fmt(t.income); g('h-costs').textContent=fmt(t.fcost+t.expenses); g('h-profit').textContent=fmt(t.profit); var pending=DB.clients.reduce(function(s,c){return s+Math.max(0,clientBalance(c.id))},0); g('h-pending').textContent=fmt(pending); g('h-ords').textContent=t.orders.length; g('h-delivered').textContent=t.orders.filter(function(o){return o.status==='تم التوصيل للعميل'}).length;
  g('h-status').innerHTML=STATUSES.map(function(st){ var cnt=t.orders.filter(function(o){return (o.status||'تحت التنفيذ')===st}).length; return '<div class="row"><div class="row-name">'+statusBadge(st)+' '+st+'</div><div class="row-val">'+cnt+'</div></div>'; }).join('');
  var recent=DB.orders.slice().sort(function(a,b){return String(b.date||'').localeCompare(String(a.date||''))}).slice(0,6); var ro=g('h-recent-orders'); ro.innerHTML=recent.length?recent.map(orderCard).join(''):'<div class="empty"><i class="ti ti-package"></i><p>لا توجد أوردرات بعد</p></div>';
  var dues=DB.factories.map(function(f){return{f:f,bal:factoryBalance(f.id)}}).filter(function(x){return x.bal>0}); g('h-factory-dues').innerHTML=dues.length?dues.map(function(d){return '<div class="row"><div class="row-name">'+safe(d.f.name)+'</div><span class="badge bg-red">'+fmt(d.bal)+'</span></div>'}).join(''):'<p class="muted tiny">لا توجد مديونيات للمصانع</p>'; }

function orderCard(o){ var c=DB.clients.find(function(x){return x.id===o.clientId})||{name:'؟'}; var f=DB.factories.find(function(x){return x.id===o.factoryId})||{name:'؟'}; var fp=factoryTotalForOrder(o); var profit=profitForOrder(o); return '<div class="card clickable" onclick="openOrderDetail(\''+o.id+'\')">'
  +'<div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px;gap:8px"><div><div class="row-name">'+safe(o.code)+' '+(o.name?'<span class="muted tiny">· '+safe(o.name)+'</span>':'')+'</div><div class="row-sub">'+safe(c.name)+' · '+safe(f.name)+'</div></div><div style="display:flex;flex-direction:column;align-items:flex-end;gap:6px">'+statusBadge(o.status)+'<label class="select-row tiny muted" onclick="event.stopPropagation()"><input type="checkbox" class="order-export-check" value="'+o.id+'"> تحديد</label></div></div>'
  +'<div style="display:flex;gap:10px;flex-wrap:wrap;font-size:12px;color:#888;margin-bottom:8px"><span><i class="ti ti-stack"></i> مبدئي '+countFmt(o.qty)+'</span><span><i class="ti ti-checkup-list"></i> نهائي '+countFmt(billQty(o))+'</span>'+(o.size?'<span><i class="ti ti-ruler"></i> '+safe(o.size)+'</span>':'')+(o.date?'<span><i class="ti ti-calendar"></i> '+safe(o.date)+'</span>':'')+'</div>'
  +'<div style="display:flex;justify-content:space-between;border-top:1px solid #f2f2f2;padding-top:8px;gap:8px;flex-wrap:wrap"><span class="tiny">عميل: <b class="success">'+fmt(clientTotalForOrder(o))+'</b></span><span class="tiny">عربون: <b class="blue-t">'+fmt(num(o.deposit))+'</b></span><span class="tiny">مستحق: <b class="warn">'+fmt(Math.max(0,clientTotalForOrder(o)-num(o.deposit)))+'</b></span><span class="tiny">مصنع: <b class="danger">'+fmt(fp)+'</b></span><span class="tiny">ربح: <b class="'+(profit>=0?'success':'danger')+'">'+fmt(profit)+'</b></span></div></div>'; }
function renderOrders(){
  g('status-chips').innerHTML=[['all','الكل']].concat(STATUSES.map(function(s){return [s,s]})).map(function(x){return '<button class="chip '+(selStatus===x[0]?'active':'')+'" onclick="selStatus=\''+x[0]+'\';renderOrders()">'+x[1]+'</button>'}).join('');
  periodChips('period-chips',selPeriod,'setOrderPeriod');
  var chips=[{id:'all',name:'كل المصانع'}].concat(DB.factories); g('order-chips').innerHTML=chips.map(function(f){return '<button class="chip '+(selFac===f.id?'active':'')+'" onclick="selFac=\''+f.id+'\';renderOrders()">'+safe(f.name)+'</button>'}).join('');
  var q=(g('q-orders')?g('q-orders').value:'').toLowerCase(); var orders=DB.orders.slice().sort(function(a,b){return String(b.date||'').localeCompare(String(a.date||''))}); if(selStatus!=='all') orders=orders.filter(function(o){return (o.status||'تحت التنفيذ')===selStatus}); if(selFac!=='all') orders=orders.filter(function(o){return o.factoryId===selFac}); orders=orders.filter(function(o){return dateMatches(o.date,selPeriod,curMonth())}); if(q) orders=orders.filter(function(o){ var c=DB.clients.find(function(x){return x.id===o.clientId})||{name:''}; var f=DB.factories.find(function(x){return x.id===o.factoryId})||{name:''}; return String(o.code).toLowerCase().includes(q)||String(c.name).toLowerCase().includes(q)||String(f.name).toLowerCase().includes(q)||String(o.name).toLowerCase().includes(q); });
  g('orders-list').innerHTML=orders.length?orders.map(orderCard).join(''):'<div class="empty"><i class="ti ti-package"></i><p>لا توجد أوردرات حسب الفلتر الحالي</p></div>'; }
function setOrderPeriod(p){ selPeriod=p; renderOrders(); }

function renderClients(){ var q=(g('q-clients')?g('q-clients').value:'').toLowerCase(); var clients=DB.clients.filter(function(c){return !q||String(c.name).toLowerCase().includes(q)||String(c.phone||'').includes(q)}); g('clients-list').innerHTML=clients.length?clients.map(function(c){ var bal=clientBalance(c.id), total=clientTotal(c.id)+num(c.debt), paid=clientPaid(c.id), pct=total>0?Math.min(100,Math.round(paid/total*100)):0, ords=DB.orders.filter(function(o){return o.clientId===c.id}).length; return '<div class="card clickable" onclick="openClientDetail(\''+c.id+'\')"><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px"><div style="display:flex;align-items:center;gap:10px"><div class="avatar av-blue">'+safe(c.name.charAt(0))+'</div><div><div class="row-name">'+safe(c.name)+'</div><div class="row-sub">'+safe(c.phone||'بدون هاتف')+'</div></div></div><span class="badge '+(bal>0?'bg-red':bal<0?'bg-green':'bg-gray')+'">'+(bal>0?fmt(bal)+' باقي':bal<0?fmt(-bal)+' رصيد':'مكتمل')+'</span></div><div class="prog"><div class="prog-fill" style="width:'+pct+'%"></div></div><div class="tiny muted" style="margin-top:4px">'+pct+'% مدفوع · '+ords+' أوردر</div></div>'; }).join(''):'<div class="empty"><i class="ti ti-users"></i><p>لا يوجد عملاء</p></div>'; }

function renderFactories(){ g('factories-list').innerHTML=DB.factories.map(function(f){ var total=factoryTotal(f.id)+num(f.debt), paid=factoryPaid(f.id), bal=total-paid, ords=factoryOrders(f.id); return '<div class="card"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px"><div style="display:flex;align-items:center;gap:10px"><div class="avatar av-green">'+safe(f.name.charAt(0))+'</div><div><div class="row-name">'+safe(f.name)+'</div><div class="row-sub">'+ords.length+' أوردر</div></div></div><span class="badge '+(bal>0?'bg-red':'bg-green')+'">'+(bal>0?fmt(bal)+' باقي':'مكتمل')+'</span></div><div class="stat-grid"><div class="stat-box gray"><div class="sl">إجمالي المستحق</div><div class="sv">'+fmt(total)+'</div></div><div class="stat-box green"><div class="sl">المدفوع شامل العربون</div><div class="sv">'+fmt(paid)+'</div></div></div><div class="btn-row"><button class="btn full" onclick="openFactoryDetail(\''+f.id+'\')"><i class="ti ti-list-details"></i> أوردرات المصنع</button><button class="btn green full" onclick="openTransferForm(\''+f.id+'\')"><i class="ti ti-send"></i> تحويل</button></div><div class="btn-row"><button class="btn amber full" onclick="openFactoryForm(\''+f.id+'\')"><i class="ti ti-edit"></i> تعديل المصنع</button><button class="btn red-out full" onclick="deleteFactory(\''+f.id+'\')"><i class="ti ti-trash"></i> حذف المصنع</button></div></div>'; }).join(''); }

function renderReports(){ periodChips('rep-periods',repPeriod,'setRepPeriod'); buildMonthTabs('rep-months',selRepMonth,'selectRepMonth'); var t=periodTotals(repPeriod,selRepMonth); g('rep-stats').innerHTML='<div class="stat-box green"><div class="sl">إجمالي الدخل</div><div class="sv">'+fmt(t.income)+'</div></div><div class="stat-box red"><div class="sl">تكلفة المصانع</div><div class="sv">'+fmt(t.fcost)+'</div></div><div class="stat-box red"><div class="sl">مصروفات أخرى</div><div class="sv">'+fmt(t.expenses)+'</div></div><div class="stat-box amber"><div class="sl">صافي الربح</div><div class="sv">'+fmt(t.profit)+'</div></div>';
  var byFac={}; t.orders.forEach(function(o){byFac[o.factoryId]=(byFac[o.factoryId]||0)+clientTotalForOrder(o)}); var facRows=Object.keys(byFac).map(function(fid){var f=DB.factories.find(function(x){return x.id===fid})||{name:'؟'}; return{name:f.name,tot:byFac[fid],id:fid}}).sort(function(a,b){return b.tot-a.tot}); g('rep-fac').innerHTML=facRows.length?facRows.map(function(r){return '<div class="row"><div><div class="row-name">'+safe(r.name)+'</div><button class="btn small" onclick="openFactoryDetail(\''+r.id+'\')">تفاصيل</button></div><div class="row-val">'+fmt(r.tot)+'</div></div>'}).join(''):'<p class="muted tiny">لا توجد بيانات</p>';
  var byC={}; t.orders.forEach(function(o){byC[o.clientId]=(byC[o.clientId]||0)+clientTotalForOrder(o)}); var cRows=Object.keys(byC).map(function(cid){var c=DB.clients.find(function(x){return x.id===cid})||{name:'؟'}; return{name:c.name,tot:byC[cid],id:cid}}).sort(function(a,b){return b.tot-a.tot}); g('rep-clients').innerHTML=cRows.length?cRows.map(function(r){return '<div class="row"><div><div class="row-name">'+safe(r.name)+'</div><button class="btn small" onclick="openClientDetail(\''+r.id+'\')">تفاصيل</button></div><div class="row-val">'+fmt(r.tot)+'</div></div>'}).join(''):'<p class="muted tiny">لا توجد بيانات</p>';
  g('rep-status').innerHTML=STATUSES.map(function(st){var cnt=t.orders.filter(function(o){return (o.status||'تحت التنفيذ')===st}).length; return '<div class="row"><div>'+statusBadge(st)+'</div><div class="row-val">'+cnt+'</div></div>'}).join('');
  var ex=periodExpenses(repPeriod,selRepMonth); g('rep-exp').innerHTML=ex.length?ex.map(function(e){return '<div class="row"><div><div class="row-name">'+safe(e.type)+'</div><div class="row-sub">'+safe(e.date||'')+(e.note?' · '+safe(e.note):'')+'</div></div><div class="row-val danger">'+fmt(e.amount)+'</div></div>'}).join(''):'<p class="muted tiny">لا توجد مصروفات</p>'; }

// ================= DETAILS =================
function receiptLink(r){ return r&&r.data?'<a class="btn small" href="'+r.data+'" target="_blank"><i class="ti ti-photo"></i> عرض الإيصال</a>':'' }
function openClientDetail(cid){ var c=DB.clients.find(function(x){return x.id===cid}); if(!c)return; var orders=DB.orders.filter(function(o){return o.clientId===cid}); var payments=DB.payments.filter(function(p){return p.clientId===cid}); var total=clientTotal(cid)+num(c.debt), paid=clientPaid(cid), bal=clientBalance(cid); g('client-detail-body').innerHTML='<div class="drawer-handle"></div><div style="display:flex;align-items:center;gap:12px;margin-bottom:14px"><div class="avatar av-blue" style="width:46px;height:46px;font-size:17px">'+safe(c.name.charAt(0))+'</div><div><div style="font-size:17px;font-weight:900">'+safe(c.name)+'</div><div class="row-sub">'+safe(c.phone||'')+(c.addr?' · '+safe(c.addr):'')+'</div></div></div><div class="stat-grid"><div class="stat-box blue"><div class="sl">إجمالي الطلبات</div><div class="sv">'+fmt(total)+'</div></div><div class="stat-box green"><div class="sl">المدفوع شامل العربون</div><div class="sv">'+fmt(paid)+'</div></div></div><div class="stat-box '+(bal>0?'red':'green')+'" style="margin-bottom:12px"><div class="sl">الرصيد</div><div class="sv">'+(bal>0?fmt(bal)+' باقي':bal<0?fmt(-bal)+' رصيد إضافي':'الحساب منتهي')+'</div></div><button class="btn green full" style="margin-bottom:14px" onclick="closeDrawer(\'dr-client-detail\');openPaymentForm(\''+cid+'\')"><i class="ti ti-plus"></i> تسجيل دفعة</button><button class="btn blue full" style="margin-bottom:14px" onclick="exportClientReportExcel(\''+cid+'\')"><i class="ti ti-file-spreadsheet"></i> تقرير العميل Excel</button><div class="sec-label">الأوردرات ('+orders.length+')</div>'+(orders.length?orders.map(function(o){return '<div class="row clickable" onclick="closeDrawer(\'dr-client-detail\');openOrderDetail(\''+o.id+'\')"><div><div class="row-name">'+safe(o.code)+' '+statusBadge(o.status)+'</div><div class="row-sub">'+safe(o.date||'')+' · عدد نهائي '+countFmt(billQty(o))+'</div></div><div class="row-val">'+fmt(clientTotalForOrder(o))+'</div></div>'}).join(''):'<p class="muted tiny">لا توجد أوردرات</p>')+'<div class="sec-label">الدفعات ('+payments.length+')</div>'+(payments.length?payments.map(function(p){return '<div class="row"><div><div class="row-name">'+fmt(p.amount)+'</div><div class="row-sub">'+safe(p.date||'')+(p.note?' · '+safe(p.note):'')+'</div>'+receiptLink(p.receipt)+'</div><span class="badge bg-green">مدفوع</span></div>'}).join(''):'<p class="muted tiny">لا توجد دفعات</p>')+'<button class="btn full" style="margin-top:14px" onclick="closeDrawer(\'dr-client-detail\')">إغلاق</button>'; openDrawer('dr-client-detail'); }
function openOrderDetail(id){ var o=DB.orders.find(function(x){return x.id===id}); if(!o)return; var c=DB.clients.find(function(x){return x.id===o.clientId})||{name:'؟'}; var f=DB.factories.find(function(x){return x.id===o.factoryId})||{name:'؟'}; g('order-detail-body').innerHTML='<div class="drawer-handle"></div><div class="drawer-title"><i class="ti ti-package"></i> '+safe(o.code)+'</div><div class="card"><div class="row"><div class="row-sub">الحالة</div><div>'+statusBadge(o.status)+'</div></div><div class="row"><div class="row-sub">العميل</div><div class="row-name">'+safe(c.name)+'</div></div><div class="row"><div class="row-sub">المصنع</div><div class="row-name">'+safe(f.name)+'</div></div><div class="row"><div class="row-sub">النوع</div><div>'+safe(o.type||'')+'</div></div><div class="row"><div class="row-sub">المقاس</div><div>'+safe(o.size||'—')+'</div></div><div class="row"><div class="row-sub">العدد المبدئي</div><div>'+countFmt(o.qty)+'</div></div><div class="row"><div class="row-sub">العدد النهائي للحساب</div><div class="success row-val">'+countFmt(billQty(o))+'</div></div><div class="row"><div class="row-sub">إجمالي العميل</div><div class="success row-val">'+fmt(clientTotalForOrder(o))+'</div></div><div class="row"><div class="row-sub">العربون المدفوع</div><div class="blue-t row-val">'+fmt(num(o.deposit))+'</div></div><div class="row"><div class="row-sub">المستحق بعد العربون</div><div class="warn row-val">'+fmt(Math.max(0,clientTotalForOrder(o)-num(o.deposit)))+'</div></div><div class="row"><div class="row-sub">إجمالي المصنع</div><div class="danger row-val">'+fmt(factoryTotalForOrder(o))+'</div></div><div class="row"><div class="row-sub">الربح</div><div class="'+(profitForOrder(o)>=0?'success':'danger')+' row-val">'+fmt(profitForOrder(o))+'</div></div></div><div class="field"><label>تغيير الحالة سريعاً</label><select onchange="changeOrderStatus(\''+o.id+'\',this.value)">'+STATUSES.map(function(s){return '<option '+(s===(o.status||'تحت التنفيذ')?'selected':'')+'>'+s+'</option>'}).join('')+'</select></div><div class="btn-row"><button class="btn primary" onclick="openOrderForm(\''+o.id+'\')"><i class="ti ti-edit"></i> تعديل الأوردر</button><button class="btn amber" onclick="openFactoryPrices(\''+o.id+'\')"><i class="ti ti-building-factory"></i> بيانات المصنع</button></div><div class="btn-row"><button class="btn blue" onclick="exportQuoteExcel(\''+o.id+'\')"><i class="ti ti-file-spreadsheet"></i> عرض سعر Excel</button><button class="btn green" onclick="exportInvoiceExcel(\''+o.id+'\')"><i class="ti ti-file-invoice"></i> فاتورة Excel</button></div><button class="btn red-out full" onclick="deleteOrder(\''+o.id+'\')"><i class="ti ti-trash"></i> حذف الأوردر نهائياً</button><button class="btn full" style="margin-top:8px" onclick="closeDrawer(\'dr-order-detail\')">إغلاق</button>'; openDrawer('dr-order-detail'); }
function openFactoryDetail(fid){ var f=DB.factories.find(function(x){return x.id===fid}); if(!f)return; var ords=factoryOrders(fid).sort(function(a,b){return String(b.date||'').localeCompare(String(a.date||''))}); var rows=ords.map(function(o){ var c=DB.clients.find(function(x){return x.id===o.clientId})||{name:'؟'}; return '<tr><td><input type="checkbox" class="fac-export-check" value="'+o.id+'"></td><td>'+safe(o.code)+'</td><td>'+safe(c.name)+'</td><td>'+statusBadge(o.status)+'</td><td>'+safe(o.size||'')+'</td><td>'+countFmt(o.qty)+'</td><td>'+countFmt(billQty(o))+'</td><td>'+fmt(num(o.fPrice))+'</td><td>'+fmt(factoryTotalForOrder(o))+'</td><td>'+fmt(clientTotalForOrder(o))+'</td></tr>'; }).join(''); var transfers=DB.transfers.filter(function(t){return t.factoryId===fid}); g('factory-detail-body').innerHTML='<div class="drawer-handle"></div><div class="drawer-title"><i class="ti ti-building-factory-2"></i> '+safe(f.name)+'</div><div class="stat-grid"><div class="stat-box amber"><div class="sl">مستحق المصنع</div><div class="sv">'+fmt(factoryTotal(fid)+num(f.debt))+'</div></div><div class="stat-box green"><div class="sl">المدفوع</div><div class="sv">'+fmt(factoryPaid(fid))+'</div></div></div><div class="btn-row"><button class="btn blue" onclick="exportSelectedFactoryOrders(\''+fid+'\')"><i class="ti ti-file-spreadsheet"></i> تصدير المحدد</button><button class="btn green" onclick="openTransferForm(\''+fid+'\')"><i class="ti ti-send"></i> تحويل</button></div><div class="table-wrap"><table class="mini-table"><thead><tr><th>تحديد</th><th>كود</th><th>عميل</th><th>حالة</th><th>مقاس</th><th>مبدئي</th><th>نهائي</th><th>سعر مصنع</th><th>إجمالي مصنع</th><th>إجمالي عميل</th></tr></thead><tbody>'+(rows||'<tr><td colspan="10">لا توجد أوردرات</td></tr>')+'</tbody></table></div><div class="sec-label">تحويلات المصنع</div>'+(transfers.length?transfers.map(function(t){return '<div class="row"><div><div class="row-name">'+fmt(t.amount)+' · '+safe(t.type||'')+'</div><div class="row-sub">'+safe(t.date||'')+(t.note?' · '+safe(t.note):'')+'</div>'+receiptLink(t.receipt)+'</div><span class="badge bg-green">تحويل</span></div>'}).join(''):'<p class="muted tiny">لا توجد تحويلات</p>')+'<button class="btn full" style="margin-top:14px" onclick="closeDrawer(\'dr-factory-detail\')">إغلاق</button>'; openDrawer('dr-factory-detail'); }


// ================= EXCEL EXPORTS — TEMPLATE STYLE =================
var TEMPLATE_XLSX_BASE64='';
var EXCEL_MIME='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
function hasExcelJS(){ if(!window.ExcelJS){ toast('مكتبة Excel لم تتحمل. افتح التطبيق والإنترنت متصل ثم حاول مرة أخرى.'); return false } return true }
function base64ToArrayBuffer(b64){ var bin=atob(b64), len=bin.length, bytes=new Uint8Array(len); for(var i=0;i<len;i++) bytes[i]=bin.charCodeAt(i); return bytes.buffer; }
async function makeTemplateWorkbook(){ var wb=new ExcelJS.Workbook(); await wb.xlsx.load(base64ToArrayBuffer(TEMPLATE_XLSX_BASE64)); wb.views=[{rightToLeft:true}]; wb.worksheets.forEach(function(ws){ ws.views=[{rightToLeft:true}]; }); return wb; }
function clearRange(ws,r1,r2,c1,c2){ for(var r=r1;r<=r2;r++){ for(var c=c1;c<=c2;c++){ ws.getCell(r,c).value=null; } } }
function setv(ws,r,c,v){ ws.getCell(r,c).value=(v===undefined?null:v); }
function styleHeaderCell(cell,fill){ cell.font={bold:true,color:{argb:'FFFFFFFF'},size:10}; cell.fill={type:'pattern',pattern:'solid',fgColor:{argb:fill||'FF1A1A2E'}}; cell.alignment={horizontal:'center',vertical:'middle',wrapText:true}; cell.border={top:{style:'thin',color:{argb:'FFBDBDBD'}},left:{style:'thin',color:{argb:'FFBDBDBD'}},right:{style:'thin',color:{argb:'FFBDBDBD'}},bottom:{style:'thin',color:{argb:'FFBDBDBD'}}}; }
function styleNormalCell(cell){ cell.alignment={horizontal:'center',vertical:'middle',wrapText:true}; cell.border={top:{style:'thin',color:{argb:'FFE5E7EB'}},left:{style:'thin',color:{argb:'FFE5E7EB'}},right:{style:'thin',color:{argb:'FFE5E7EB'}},bottom:{style:'thin',color:{argb:'FFE5E7EB'}}}; }
function fmtMoneyCell(cell){ cell.numFmt='#,##0.00'; }
function downloadBlob(blob,fileName){ var url=URL.createObjectURL(blob); var a=document.createElement('a'); a.href=url; a.download=fileName; document.body.appendChild(a); a.click(); a.remove(); setTimeout(function(){URL.revokeObjectURL(url)},1200); }
async function saveExcelJSWorkbook(workbook,fileName){ var buffer=await workbook.xlsx.writeBuffer(); var blob=new Blob([buffer],{type:EXCEL_MIME}); downloadBlob(blob,fileName); if(accessToken&&DB.settings&&DB.settings.autoSync) uploadBlobToDrive(blob,fileName,EXCEL_MIME); return blob; }
