function writeDashboard(ws){
  var t=periodTotals('month',curMonth());
  setv(ws,1,1,'🏠  الداشبورد  |  نسخة محفوظة من Web App — '+todayStr());
  setv(ws,4,3,t.income); setv(ws,4,5,t.fcost);
  setv(ws,5,3,DB.payments.reduce(function(s,p){return s+num(p.amount)},0)); setv(ws,5,5,DB.transfers.reduce(function(s,t){return s+num(t.amount)},0));
  setv(ws,6,3,DB.clients.reduce(function(s,c){return s+Math.max(0,clientBalance(c.id))},0)); setv(ws,6,5,DB.factories.reduce(function(s,f){return s+Math.max(0,factoryBalance(f.id))},0));
  setv(ws,14,3,DB.expenses.reduce(function(s,e){return s+num(e.amount)},0));
  setv(ws,17,3,t.profit);
}
