function openNotify(){ var items=[]; var notPriced=DB.orders.filter(function(o){return !num(o.fPrice)||!num(o.fQty)}); if(notPriced.length) items.push('<div class="alert amber">'+notPriced.length+' أوردر محتاج بيانات المصنع النهائية</div>'); DB.clients.forEach(function(c){var b=clientBalance(c.id); if(b>0)items.push('<div class="row"><div><div class="row-name">'+safe(c.name)+'</div><div class="row-sub">باقي عليه '+fmt(b)+'</div></div><span class="badge bg-red">عميل</span></div>')}); DB.factories.forEach(function(f){var b=factoryBalance(f.id); if(b>0)items.push('<div class="row"><div><div class="row-name">'+safe(f.name)+'</div><div class="row-sub">باقي له '+fmt(b)+'</div></div><span class="badge bg-amber">مصنع</span></div>')}); g('notify-body').innerHTML=items.length?items.join(''):'<div class="empty"><i class="ti ti-bell"></i><p>لا توجد تنبيهات</p></div>'; openDrawer('dr-notify'); }

