function compressedImageFile(file,maxW,maxH,quality,cb){
  if(!file){ cb(null); return; }
  if(!/^image\//.test(file.type||'')){ toast('اختار ملف صورة فقط'); cb(null); return; }
  var reader=new FileReader();
  reader.onerror=function(){ toast('تعذر قراءة الصورة'); cb(null); };
  reader.onload=function(ev){
    var img=new Image();
    img.onerror=function(){ toast('تعذر تجهيز الصورة'); cb(null); };
    img.onload=function(){ try{
      var w=img.width,h=img.height,scale=Math.min(1,(maxW||1000)/w,(maxH||1000)/h);
      var canvas=document.createElement('canvas'); canvas.width=Math.max(1,Math.round(w*scale)); canvas.height=Math.max(1,Math.round(h*scale));
      var ctx=canvas.getContext('2d'); ctx.drawImage(img,0,0,canvas.width,canvas.height);
      var data=canvas.toDataURL('image/jpeg',quality||0.72);
      cb({name:file.name,type:'image/jpeg',size:data.length,data:data,compressed:true});
    }catch(e){ console.error(e); cb({name:file.name,type:file.type,size:file.size,data:ev.target.result,compressed:false}); } };
    img.src=ev.target.result;
  };
  reader.readAsDataURL(file);
}
