  var c=DB.clients.find(function(x){return x.id===o.clientId})||{name:'؟'}; var f=DB.factories.find(function(x){return x.id===o.factoryId})||{name:'؟'}; var linkedExp=orderExpenses(o.id); var profit=profitForOrder(o);
