    var o=null;
    if(oldId) o=(DB.orders||[]).find(function(x){return x.id===oldId});
    if(!o && oldCode) o=(DB.orders||[]).slice().reverse().find(function(x){return x.code===oldCode});
    if(o){ o.colorCount=cc||'1'; save(true); refreshAll(); }
