      if(num(o.fAk)>0){ total+=num(o.fAk); rows.push('<tr><td>'+idx+++'</td><td>'+safe(o.code||'')+'</td><td>'+safe(c.name)+'</td><td>اكلاشيه مصنع / تجهيز</td><td>-</td><td>-</td><td>1</td><td>'+money(o.fAk)+'</td><td>'+money(o.fAk)+'</td></tr>'); }
