    var all=factoryOrders(fid).slice().sort(function(a,b){return String(b.date||'').localeCompare(String(a.date||''));}); var shown=factoryOrdersFiltered(fid); var transfers=factoryTransfersFiltered(fid);
    var total=shown.reduce(function(s,o){return s+factoryTotalForOrder(o)},0), paid=transfers.reduce(function(s,t){return s+num(t.amount)},0), bal=total-paid;
    var allTotal=factoryTotal(fid)+num(f.debt), allPaid=factoryPaid(fid), allBal=allTotal-allPaid;
    var rows=shown.map(function(o){ normalizeOrderV6(o); var c=getClient(o.clientId); return '<tr><td><input type="checkbox" class="factory-order-check" value="'+safeTxt(o.id)+'"></td><td>'+safeTxt(o.code||'')+'</td><td>'+safeTxt(c.name||'')+'</td><td>'+safeTxt(itemName(o))+'</td><td>'+safeTxt(o.type||'')+'</td><td>'+safeTxt(sizeText2(o))+'</td><td>'+safeTxt(o.color||'')+'</td><td>'+safeTxt(o.handle||'بدون')+'</td><td>'+safeTxt(orderColorCountSafe(o))+'</td><td>'+safeTxt(orderFace(o))+'</td><td>'+countFmt(num(o.fQty)||num(o.qty))+'</td><td>'+money(num(o.fPrice))+'</td><td>'+money((num(o.fQty)||num(o.qty))*num(o.fPrice))+'</td></tr>'; }).join('');
