    var filterBtns=['all','week_current','week_previous','month_current','month_previous'].map(function(k){return '<button class="chip '+(factoryFilterV6.type===k?'active':'')+'" onclick="setFactoryFilterV6(\''+fid+'\',\''+k+'\')">'+({'all':'كل الأوردرات','week_current':'الأسبوع الحالي','week_previous':'الأسبوع الماضي','month_current':'الشهر الحالي','month_previous':'الشهر السابق'}[k])+'</button>';}).join('');
    $id('factory-detail-body').innerHTML='<div class="drawer-handle"></div><div class="drawer-title"><i class="ti ti-building-factory-2"></i> '+safeTxt(f.name)+'</div><div class="row-sub">كود المصنع: '+safeTxt(f.code||'')+'</div><div class="factory-period-note">فلتر المصنع يعرض مستحق ومدفوع الفترة المختارة، مع بقاء الإجمالي الكلي للمراجعة.</div><div class="account-summary-grid"><div class="stat-box amber"><div class="sl">مستحق الفترة</div><div class="sv">'+money(total)+'</div></div><div class="stat-box green"><div class="sl">مدفوع الفترة</div><div class="sv">'+money(paid)+'</div></div><div class="stat-box red"><div class="sl">المتبقى للفترة</div><div class="sv">'+money(bal)+'</div></div><div class="stat-box gray"><div class="sl">الباقي الكلي</div><div class="sv">'+money(allBal)+'</div></div></div><div class="hp-mini-note">الإجمالي الكلي: '+money(allTotal)+' · المدفوع الكلي: '+money(allPaid)+' · الباقي الكلي: '+money(allBal)+'</div><div class="factory-month-tabs">'+filterBtns+'</div><div class="doc-action-bar"><button class="btn" onclick="toggleFactoryOrdersSelection(\''+fid+'\')"><i class="ti ti-checks"></i> تحديد/إلغاء الكل</button><button class="btn blue" onclick="printSelectedFactoryStatement(\''+fid+'\')"><i class="ti ti-file-invoice"></i> كشف حساب للمحدد</button><button class="btn green" onclick="openTransferForm(\''+fid+'\')"><i class="ti ti-send"></i> تحويل</button><button class="btn" onclick="exportSelectedFactoryOrders(\''+fid+'\')"><i class="ti ti-file-spreadsheet"></i> Excel المحدد</button></div><div class="table-wrap"><table class="mini-table"><thead><tr><th>تحديد</th><th>كود</th><th>عميل</th><th>اسم الصنف</th><th>النوع</th><th>المقاس</th><th>لون الشنطة</th><th>لون اليد</th><th>عدد الألوان</th><th>وجه</th><th>الكمية</th><th>سعر مصنع</th><th>القيمة</th></tr></thead><tbody>'+(rows||'<tr><td colspan="13">لا توجد أوردرات في هذه الفترة</td></tr>')+'</tbody></table></div><div class="hp-mini-note">المعروض الآن: '+shown.length+' من أصل '+all.length+' أوردر للمصنع.</div><div class="sec-label">تحويلات الفترة</div><div class="card">'+transferHtml+'</div><button class="btn full" style="margin-top:14px" onclick="closeDrawer(\'dr-factory-detail\')">إغلاق</button>';
    openDrawer('dr-factory-detail');
