  async function exportOrdersDocExcel(orders,mode,filename){
    if(typeof ExcelJS==='undefined'){ toast('مكتبة Excel لم تحمل بعد. افتح الإنترنت أو استخدم طباعة PDF.'); return; }
    var wb=new ExcelJS.Workbook(), ws=wb.addWorksheet(mode==='quote'?'عرض سعر':'فاتورة بيع'); ws.views=[{rightToLeft:true}]; ws.pageSetup={orientation:'landscape',paperSize:9,fitToPage:true,fitToWidth:1,fitToHeight:0};
    ws.addRow(['Haydarpack - حيدر باك']); ws.addRow([COMPANY_LINE]); ws.addRow([]);
    var headers=['كود الأوردر','اسم الصنف','نوع الشنطة','لون الشنطة','لون اليد','عدد الألوان','وجه','الكمية','سعر الشنطة','القيمة']; ws.addRow(headers);
    var tr=clientRows(orders,mode); var tmp=document.createElement('tbody'); tmp.innerHTML=tr.rows; Array.prototype.slice.call(tmp.querySelectorAll('tr')).forEach(function(row){ ws.addRow(Array.prototype.slice.call(row.children).map(function(td){return td.textContent;})); });
    ws.addRow([]); ws.addRow(['الإجمالي','','','','','','','','',money(tr.total)]); ws.columns.forEach(function(c){c.width=18}); ws.getRow(1).font={bold:true,size:16}; ws.getRow(4).font={bold:true}; ws.getRow(4).fill={type:'pattern',pattern:'solid',fgColor:{argb:'FFD9D9D9'}}; ws.eachRow(function(r){r.eachCell(function(c){c.alignment={vertical:'middle',horizontal:'center',wrapText:true};c.border={top:{style:'thin'},left:{style:'thin'},bottom:{style:'thin'},right:{style:'thin'}};});});
    var buf=await wb.xlsx.writeBuffer(); var blob=new Blob([buf],{type:'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'}); var a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=filename; a.click(); setTimeout(function(){URL.revokeObjectURL(a.href)},1000);
  }
  exportQuoteExcel=function(id){ var o=getOrder(id); if(!o)return; exportOrdersDocExcel([o],'quote','quote_'+(o.code||'order')+'.xlsx'); };
  exportInvoiceExcel=function(id){ var o=getOrder(id); if(!o)return; exportOrdersDocExcel([o],'invoice','invoice_'+(o.code||'order')+'.xlsx'); };

