  var hpBackupTimer=null;
  var hpSnapshotTimer=null;
  var hpLastValidJson='';
  var hpBackupWriting=false;
  var hpPendingBackup=false;
  var hpSafetyInitStarted=false;
  var hpPendingPreUpdateText='';

  function hpPad(v){return String(v).padStart(2,'0')}
  function hpLocalDate(d){d=d||new Date();return d.getFullYear()+'-'+hpPad(d.getMonth()+1)+'-'+hpPad(d.getDate())}
  function hpFileStamp(d){d=d||new Date();return hpLocalDate(d)+'_'+hpPad(d.getHours())+'-'+hpPad(d.getMinutes())+'-'+hpPad(d.getSeconds())}
  function hpNow(){return new Date().toISOString()}
  function hpHash(str){var h=2166136261;for(var i=0;i<str.length;i++){h^=str.charCodeAt(i);h=Math.imul(h,16777619)}return ('00000000'+(h>>>0).toString(16)).slice(-8)}
  function hpClone(v){return JSON.parse(JSON.stringify(v))}
  function hpSafeText(v){return typeof safe==='function'?safe(v):String(v==null?'':v)}
  function hpCounts(db){return {clients:(db.clients||[]).length,factories:(db.factories||[]).length,orders:(db.orders||[]).length,payments:(db.payments||[]).length,transfers:(db.transfers||[]).length,expenses:(db.expenses||[]).length}}
  function hpHasBusinessData(db){var c=hpCounts(db||{});return c.clients+c.orders+c.payments+c.transfers+c.expenses>0}

  function hpEnsureShape(db){
    if(!db||typeof db!=='object'||Array.isArray(db)) throw new Error('قاعدة البيانات ليست كائناً صالحاً');
    ['clients','factories','orders','payments','transfers','expenses'].forEach(function(k){if(!Array.isArray(db[k]))db[k]=[]});
    if(!Array.isArray(db.capitalMoves))db.capitalMoves=[];
    if(!db.settings||typeof db.settings!=='object'||Array.isArray(db.settings))db.settings={};
    if(!db.settings.dataSafety||typeof db.settings.dataSafety!=='object')db.settings.dataSafety={};
    db.settings.autoSync=false;
    db.version=Math.max(Number(db.version)||0,HP_SCHEMA_VERSION);
    return db;
  }

  function hpFiniteNonNegative(v){if(v==null||v==='')return true;var x=Number(v);return Number.isFinite(x)&&x>=0}
  function hpValidDate(v){return !v||/^\d{4}-\d{2}-\d{2}$/.test(String(v))}
  function hpValidateDatabase(db){
    var errors=[],warnings=[];
    try{hpEnsureShape(db)}catch(e){return {ok:false,errors:[e.message],warnings:[],counts:{}}}
    var counts=hpCounts(db);
    function idsFor(arr,label){var set=new Set();arr.forEach(function(x,i){if(!x||typeof x!=='object'){errors.push(label+' رقم '+(i+1)+' غير صالح');return}var id=String(x.id||'');if(!id){errors.push(label+' رقم '+(i+1)+' بدون ID')}else if(set.has(id)){errors.push('ID مكرر في '+label+': '+id)}else set.add(id)});return set}
    var clientIds=idsFor(db.clients,'العملاء');
    var factoryIds=idsFor(db.factories,'المصانع');
    var orderIds=idsFor(db.orders,'الأوردرات');
    idsFor(db.payments,'دفعات العملاء');idsFor(db.transfers,'تحويلات المصانع');idsFor(db.expenses,'المصروفات');idsFor(db.capitalMoves,'حركات رأس المال');
    var codes=new Set();
    db.orders.forEach(function(o,i){var label='الأوردر رقم '+(i+1);var code=String(o.code||'').trim();if(!code)warnings.push(label+' بدون كود');else if(codes.has(code))errors.push('كود أوردر مكرر: '+code);else codes.add(code);if(!clientIds.has(String(o.clientId||'')))errors.push((code||label)+' مرتبط بعميل غير موجود');if(!factoryIds.has(String(o.factoryId||'')))errors.push((code||label)+' مرتبط بمصنع غير موجود');['qty','fQty','price','aklashe','deposit','fPrice','fAk'].forEach(function(k){if(!hpFiniteNonNegative(o[k]))errors.push((code||label)+' به قيمة غير صحيحة في '+k)});if(!hpValidDate(o.date))warnings.push((code||label)+' به تاريخ غير قياسي')});
    db.clients.forEach(function(c){if(!String(c.name||'').trim())warnings.push('عميل بدون اسم: '+String(c.id||''));if(!hpFiniteNonNegative(c.debt))errors.push('مديونية عميل غير صحيحة: '+String(c.name||c.id||''))});
    db.factories.forEach(function(f){if(!String(f.name||'').trim())warnings.push('مصنع بدون اسم: '+String(f.id||''));if(!hpFiniteNonNegative(f.debt))errors.push('مديونية مصنع غير صحيحة: '+String(f.name||f.id||''))});
    db.payments.forEach(function(p){if(!clientIds.has(String(p.clientId||'')))errors.push('دفعة مرتبطة بعميل غير موجود: '+String(p.id||''));if(!hpFiniteNonNegative(p.amount)||Number(p.amount)<=0)errors.push('قيمة دفعة غير صحيحة: '+String(p.id||''));if(!hpValidDate(p.date))warnings.push('تاريخ دفعة غير قياسي: '+String(p.id||''))});
    db.transfers.forEach(function(t){if(!factoryIds.has(String(t.factoryId||'')))errors.push('تحويل مرتبط بمصنع غير موجود: '+String(t.id||''));if(!hpFiniteNonNegative(t.amount)||Number(t.amount)<=0)errors.push('قيمة تحويل غير صحيحة: '+String(t.id||''));if(!hpValidDate(t.date))warnings.push('تاريخ تحويل غير قياسي: '+String(t.id||''))});
    db.expenses.forEach(function(e){if(e.orderId&&!orderIds.has(String(e.orderId)))warnings.push('مصروف مرتبط بأوردر محذوف: '+String(e.id||''));if(!hpFiniteNonNegative(e.amount)||Number(e.amount)<=0)errors.push('قيمة مصروف غير صحيحة: '+String(e.id||''));if(!hpValidDate(e.date))warnings.push('تاريخ مصروف غير قياسي: '+String(e.id||''))});
    db.capitalMoves.forEach(function(m){if(!hpFiniteNonNegative(m.amount)||Number(m.amount)<=0)errors.push('قيمة حركة رأس مال غير صحيحة: '+String(m.id||''));if(!hpValidDate(m.date))warnings.push('تاريخ حركة رأس مال غير قياسي: '+String(m.id||''))});
    return {ok:errors.length===0,errors:errors,warnings:warnings,counts:counts};
  }

  function hpBusinessString(db){var c=hpClone(db);if(c.settings)delete c.settings.dataSafety;return JSON.stringify(c)}
  function hpPrepareMetadata(){
    hpEnsureShape(DB);
    var ds=DB.settings.dataSafety;
    var contentHash=hpHash(hpBusinessString(DB));
    if(ds.contentHash!==contentHash){ds.revision=(Number(ds.revision)||0)+1;ds.lastSavedAt=hpNow();ds.contentHash=contentHash}
    if(!ds.lastSavedAt)ds.lastSavedAt=hpNow();
    ds.appVersion=HP_APP_VERSION;ds.schemaVersion=HP_SCHEMA_VERSION;
    DB.version=HP_SCHEMA_VERSION;
    return ds;
  }

  function hpEnvelope(data){
    var copy=hpClone(data||DB);hpEnsureShape(copy);var ds=copy.settings.dataSafety||{};var payload=JSON.stringify(copy);
    return {format:'HayderPackBackup',formatVersion:1,appVersion:HP_APP_VERSION,schemaVersion:HP_SCHEMA_VERSION,exportedAt:hpNow(),revision:Number(ds.revision)||0,updatedAt:ds.lastSavedAt||'',counts:hpCounts(copy),checksum:hpHash(payload),data:copy};
  }
  function hpParseBackupText(text){
    var parsed=JSON.parse(text);var data=parsed&&parsed.format==='HayderPackBackup'?parsed.data:parsed;if(!data||typeof data!=='object')throw new Error('ملف النسخة الاحتياطية غير صالح');
    if(parsed&&parsed.format==='HayderPackBackup'&&parsed.checksum){var actual=hpHash(JSON.stringify(data));if(actual!==parsed.checksum)throw new Error('الملف ناقص أو تم تعديله؛ فشل فحص البصمة')}
    hpEnsureShape(data);var report=hpValidateDatabase(data);if(!report.ok)throw new Error('النسخة بها أخطاء: '+report.errors.slice(0,3).join(' — '));
    return {envelope:parsed&&parsed.format==='HayderPackBackup'?parsed:hpEnvelope(data),data:data,report:report};
  }

  function hpOpenIDB(){return new Promise(function(resolve,reject){if(!window.indexedDB){reject(new Error('IndexedDB غير متاح'));return}var req=indexedDB.open(HP_IDB_NAME,HP_IDB_VERSION);req.onupgradeneeded=function(){var db=req.result;if(!db.objectStoreNames.contains('kv'))db.createObjectStore('kv',{keyPath:'key'});if(!db.objectStoreNames.contains('snapshots'))db.createObjectStore('snapshots',{keyPath:'id'})};req.onsuccess=function(){resolve(req.result)};req.onerror=function(){reject(req.error)}})}
  async function hpIDBGet(key){var db=await hpOpenIDB();return new Promise(function(resolve,reject){var tx=db.transaction('kv','readonly'),r=tx.objectStore('kv').get(key);r.onsuccess=function(){resolve(r.result?r.result.value:null)};r.onerror=function(){reject(r.error)};tx.oncomplete=function(){db.close()}})}
  async function hpIDBSet(key,value){var db=await hpOpenIDB();return new Promise(function(resolve,reject){var tx=db.transaction('kv','readwrite');tx.objectStore('kv').put({key:key,value:value});tx.oncomplete=function(){db.close();resolve()};tx.onerror=function(){db.close();reject(tx.error)}})}
  async function hpIDBDelete(key){var db=await hpOpenIDB();return new Promise(function(resolve,reject){var tx=db.transaction('kv','readwrite');tx.objectStore('kv').delete(key);tx.oncomplete=function(){db.close();resolve()};tx.onerror=function(){db.close();reject(tx.error)}})}
  async function hpStoreSnapshotJson(json,reason){
    try{var obj=JSON.parse(json),ds=(obj.settings&&obj.settings.dataSafety)||{},rev=Number(ds.revision)||0,db=await hpOpenIDB();await new Promise(function(resolve,reject){var tx=db.transaction('snapshots','readwrite'),st=tx.objectStore('snapshots');st.put({id:'s'+Date.now()+'-'+rev,createdAt:hpNow(),revision:rev,reason:reason||'auto',json:json});tx.oncomplete=resolve;tx.onerror=function(){reject(tx.error)}});var all=await new Promise(function(resolve,reject){var tx=db.transaction('snapshots','readonly'),r=tx.objectStore('snapshots').getAll();r.onsuccess=function(){resolve(r.result||[])};r.onerror=function(){reject(r.error)}});all.sort(function(a,b){return String(b.createdAt).localeCompare(String(a.createdAt))});if(all.length>6){await new Promise(function(resolve,reject){var tx=db.transaction('snapshots','readwrite'),st=tx.objectStore('snapshots');all.slice(6).forEach(function(x){st.delete(x.id)});tx.oncomplete=resolve;tx.onerror=function(){reject(tx.error)}})}db.close()}catch(e){console.warn('Local snapshot skipped',e)}
  }
  function hpScheduleSnapshot(json,reason){clearTimeout(hpSnapshotTimer);hpSnapshotTimer=setTimeout(function(){hpStoreSnapshotJson(json,reason||'auto')},500)}

  function hpSetStatus(state,msg){if(typeof setSyncState==='function')setSyncState(state,msg);var el=document.getElementById('sync-status');if(el)el.textContent=msg||''}
  function hpUpdateSafetyUI(){
    var ds=(DB.settings&&DB.settings.dataSafety)||{},folder=document.getElementById('backup-folder-status'),last=document.getElementById('backup-last-status'),rev=document.getElementById('data-revision-status');
    if(folder)folder.textContent=hpBackupDirHandle?('مختار: '+(hpBackupDirHandle.name||'Backups')):'لم يتم اختياره';
    var meta=null;try{meta=JSON.parse(localStorage.getItem('hayder_pack_backup_meta')||'null')}catch(e){}
    if(last)last.textContent=meta&&meta.at?new Date(meta.at).toLocaleString('ar-EG'):'لا توجد بعد';
    if(rev)rev.textContent=String(Number(ds.revision)||0);
    var warning=document.getElementById('backup-browser-warning');if(warning){warning.innerHTML=window.showDirectoryPicker?'':'<div class="alert red">المتصفح ده لا يدعم اختيار فولدر للحفظ التلقائي. استخدم Google Chrome أو Microsoft Edge، واستخدم زر تنزيل نسخة على الجهاز.</div>'}
  }

  async function hpPermission(handle,request){if(!handle)return false;try{var q=await handle.queryPermission({mode:'readwrite'});if(q==='granted')return true;if(request){q=await handle.requestPermission({mode:'readwrite'});return q==='granted'}}catch(e){console.warn(e)}return false}
  async function hpWriteText(handle,name,text){var fileHandle=await handle.getFileHandle(name,{create:true}),w=await fileHandle.createWritable();await w.write(text);await w.close()}
  async function hpReadText(handle,name){var fileHandle=await handle.getFileHandle(name),file=await fileHandle.getFile();return file.text()}
  async function hpCleanupDaily(handle){try{var names=[];for await(var entry of handle.values()){if(entry.kind==='file'&&entry.name.indexOf(HP_DAILY_PREFIX)===0&&entry.name.endsWith('.json'))names.push(entry.name)}names.sort().reverse();for(var i=30;i<names.length;i++)await handle.removeEntry(names[i])}catch(e){console.warn('Daily cleanup skipped',e)}}

  async function hpWriteFolderBackup(manual,makeManualFile){
    if(!hpBackupDirHandle){hpSetStatus('','محفوظ محلياً — اختار فولدر Backups لتفعيل النسخة الخارجية');hpUpdateSafetyUI();return false}
    if(hpBackupWriting){hpPendingBackup=true;return false}
    if(!await hpPermission(hpBackupDirHandle,false)){hpSetStatus('work','المجلد محفوظ لكنه يحتاج تفعيل من زر «تفعيل المجلد المحفوظ»');hpUpdateSafetyUI();return false}
    hpBackupWriting=true;hpSetStatus('work','جاري حفظ النسخة الاحتياطية...');
    try{
      var report=hpValidateDatabase(DB);if(!report.ok)throw new Error('تم منع النسخ لأن قاعدة البيانات بها أخطاء');
      var env=hpEnvelope(DB),text=JSON.stringify(env,null,2),date=hpLocalDate();
      await hpWriteText(hpBackupDirHandle,HP_CURRENT_FILE,text);
      await hpWriteText(hpBackupDirHandle,HP_DAILY_PREFIX+date+'.json',text);
      if(makeManualFile)await hpWriteText(hpBackupDirHandle,HP_MANUAL_PREFIX+hpFileStamp()+'.json',text);
      if(hpPendingPreUpdateText){await hpWriteText(hpBackupDirHandle,'HayderPack_PreUpdate_'+hpFileStamp()+'.json',hpPendingPreUpdateText);hpPendingPreUpdateText=''}
      await hpCleanupDaily(hpBackupDirHandle);
      localStorage.setItem('hayder_pack_backup_meta',JSON.stringify({at:hpNow(),revision:env.revision,folder:hpBackupDirHandle.name||'Backups'}));
      hpSetStatus('ok','تم الحفظ محلياً وداخل فولدر Google Drive');hpUpdateSafetyUI();return true;
    }catch(e){console.error(e);hpSetStatus('err','فشل حفظ النسخة الخارجية — الداتا ما زالت محفوظة محلياً');if(manual)toast(e.message||'فشل حفظ النسخة');return false}
    finally{hpBackupWriting=false;if(hpPendingBackup){hpPendingBackup=false;setTimeout(function(){hpWriteFolderBackup(false,false)},300)}}
  }
  function hpScheduleFolderBackup(){clearTimeout(hpBackupTimer);hpSetStatus('work',hpBackupDirHandle?'في انتظار تحديث نسخة Google Drive...':'تم الحفظ محلياً — النسخ الخارجية غير مفعلة');hpBackupTimer=setTimeout(function(){hpWriteFolderBackup(false,false)},1200)}

  var hpPreviousSave=save;
  save=function(skipBackup){
    var previous=hpLastValidJson||localStorage.getItem(HP_LOCAL_KEY)||'';
    try{
      if(typeof reduceDBForStorage==='function')reduceDBForStorage();
      hpEnsureShape(DB);hpPrepareMetadata();
      var report=hpValidateDatabase(DB);if(!report.ok){var ve=new Error('تم منع الحفظ لحماية الداتا: '+report.errors.slice(0,3).join(' — '));ve.code='DATA_INVALID';throw ve}
      var json=JSON.stringify(DB);localStorage.setItem(HP_LOCAL_KEY,json);hpLastValidJson=json;hpScheduleSnapshot(json,'save');if(!skipBackup)hpScheduleFolderBackup();hpUpdateSafetyUI();return true;
    }catch(e){
      console.error(e);try{if(previous){DB=JSON.parse(previous);hpEnsureShape(DB);if(typeof migrate==='function')migrate();if(typeof safeRefreshAll==='function')safeRefreshAll();else if(typeof refreshAll==='function')refreshAll()}}catch(re){console.error('Rollback failed',re)}
      toast(e.code==='DATA_INVALID'?e.message:'لم يتم تسجيل التعديل؛ تم الرجوع لآخر نسخة سليمة');if(typeof showSafeError==='function')showSafeError(e.message||'تعذر الحفظ وتم الرجوع لآخر نسخة سليمة');var err=new Error('SAVE_FAILED');err.originalError=e;throw err;
    }
  };

  window.openSync=function(){hpUpdateSafetyUI();runDataHealthCheckUI();openDrawer('dr-sync')};
  window.chooseBackupFolder=async function(){
    if(!window.showDirectoryPicker){toast('استخدم Google Chrome أو Microsoft Edge');return}
    try{var h=await window.showDirectoryPicker({id:'hayder-pack-backups',mode:'readwrite',startIn:'documents'});if(!await hpPermission(h,true)){toast('لم يتم السماح بالكتابة داخل المجلد');return}hpBackupDirHandle=h;try{await hpIDBSet('backupDirHandle',h)}catch(storeErr){console.warn('تعذر تذكر المجلد بعد إغلاق المتصفح',storeErr)}hpUpdateSafetyUI();await hpWriteFolderBackup(true,true);toast('تم ربط فولدر '+(h.name||'Backups'))}catch(e){if(e&&e.name!=='AbortError'){console.error(e);toast('تعذر اختيار المجلد')}}
  };
  window.activateSavedBackupFolder=async function(){if(!hpBackupDirHandle){toast('اختار فولدر Backups أولاً');return}if(await hpPermission(hpBackupDirHandle,true)){hpUpdateSafetyUI();await hpWriteFolderBackup(true,false);toast('تم تفعيل الحفظ التلقائي')}else toast('لم يتم منح إذن الكتابة')};
  window.saveBackupNow=async function(){var report=hpValidateDatabase(DB);if(!report.ok){runDataHealthCheckUI();toast('تم منع النسخ لأن الداتا بها أخطاء');return}if(!hpBackupDirHandle){toast('اختار فولدر Backups أولاً');return}if(!await hpPermission(hpBackupDirHandle,true)){toast('فعّل إذن المجلد أولاً');return}var ok=await hpWriteFolderBackup(true,true);if(ok)toast('تم إنشاء نسخة احتياطية الآن')};
  window.downloadManualBackup=function(){try{var report=hpValidateDatabase(DB),prefix=report.ok?HP_MANUAL_PREFIX:'HayderPack_EMERGENCY_INVALID_',text=JSON.stringify(hpEnvelope(DB),null,2),blob=new Blob([text],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=prefix+hpFileStamp()+'.json';document.body.appendChild(a);a.click();a.remove();setTimeout(function(){URL.revokeObjectURL(a.href)},1500);if(report.ok)toast('تم تنزيل نسخة احتياطية');else{runDataHealthCheckUI();toast('تم تنزيل نسخة طوارئ للمراجعة بدون اعتمادها كنسخة سليمة')}}catch(e){console.error(e);toast('تعذر تنزيل النسخة')}};
