    var currentRev=Number(DB.settings&&DB.settings.dataSafety&&DB.settings.dataSafety.revision)||0,incomingRev=Number(envelope&&envelope.revision)||Number(data.settings&&data.settings.dataSafety&&data.settings.dataSafety.revision)||0;
