/* ===== CLIENTS DEFAULT SORT: LATEST ACTIVITY FIRST =====
   العميل اللي لسه اتضاف أو طلب أوردر أو دفع يظهر أول واحد في صفحة العملاء */
(function(){
  function hpClientDateMs(v){
    if(!v) return 0;
    v=String(v);
    var m=v.match(/^(\d{4})-(\d{2})-(\d{2})/);
    if(m){ return new Date(Number(m[1]),Number(m[2])-1,Number(m[3]),12,0,0).getTime() || 0; }
    var t=Date.parse(v);
    return isNaN(t)?0:t;
  }
  function hpMaxMs(){
    var mx=0;
    for(var i=0;i<arguments.length;i++) mx=Math.max(mx,hpClientDateMs(arguments[i]));
    return mx;
  }
  function hpClientActivityMs(c){
    if(!c) return 0;
    var cid=c.id;
    var mx=hpMaxMs(c.updatedAt,c.createdAt,c.date,c.month);
    (DB.orders||[]).forEach(function(o){
      if(o.clientId===cid){ mx=Math.max(mx,hpMaxMs(o.updatedAt,o.createdAt,o.date,o.deliveredAt)); }
    });
    (DB.payments||[]).forEach(function(p){
      if(p.clientId===cid){ mx=Math.max(mx,hpMaxMs(p.updatedAt,p.createdAt,p.date)); }
    });
    return mx;
  }
  window.hpClientActivityMs=hpClientActivityMs;

  var previousRenderClients=typeof renderClients==='function'?renderClients:null;
  renderClients=function(){
    var q=(g('q-clients')?g('q-clients').value:'').toLowerCase();
    var clients=(DB.clients||[]).filter(function(c){return !q||String(c.name||'').toLowerCase().includes(q)||String(c.phone||'').includes(q)});
    clients.sort(function(a,b){
      var diff=hpClientActivityMs(b)-hpClientActivityMs(a);
      if(diff) return diff;
      return String(a.name||'').localeCompare(String(b.name||''),'ar');
    });
    g('clients-list').innerHTML=clients.length?clients.map(function(c){
      var bal=clientBalance(c.id), total=clientTotal(c.id)+num(c.debt), paid=clientPaid(c.id), pct=total>0?Math.min(100,Math.round(paid/total*100)):0, ords=(DB.orders||[]).filter(function(o){return o.clientId===c.id}).length;
      return '<div class="card clickable" onclick="openClientDetail(\''+c.id+'\')"><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px"><div style="display:flex;align-items:center;gap:10px"><div class="avatar av-blue">'+safe((c.name||'?').charAt(0))+'</div><div><div class="row-name">'+safe(c.name||'')+'</div><div class="row-sub">'+safe(c.phone||'بدون هاتف')+'</div></div></div><span class="badge '+(bal>0?'bg-red':bal<0?'bg-green':'bg-gray')+'">'+(bal>0?fmt(bal)+' باقي':bal<0?fmt(-bal)+' رصيد':'مكتمل')+'</span></div><div class="prog"><div class="prog-fill" style="width:'+pct+'%"></div></div><div class="tiny muted" style="margin-top:4px">'+pct+'% مدفوع · '+ords+' أوردر</div></div>';
    }).join(''):'<div class="empty"><i class="ti ti-users"></i><p>لا يوجد عملاء</p></div>';
  };
})();


/* ===== DESKTOP DRAWER BACK BAR V10 ===== */
(function(){
  function hpDrawerTitle(drawer){
    try{
      var t=drawer&&drawer.querySelector('.drawer-title');
      return t?String(t.textContent||'').trim():'رجوع';
    }catch(e){return 'رجوع'}
  }
  function hpEnsureBackBar(id){
    var overlay=document.getElementById(id);
    if(!overlay) return;
    var drawer=overlay.querySelector('.drawer');
    if(!drawer) return;
    var old=drawer.querySelector('.hp-desktop-backbar');
    if(old) old.remove();
    var bar=document.createElement('div');
    bar.className='hp-desktop-backbar';
    bar.innerHTML='<button type="button" class="btn" data-hp-close="'+id+'">رجوع</button><div class="hp-desktop-backbar-title">'+safe(hpDrawerTitle(drawer))+'</div><button type="button" class="btn" data-hp-home>القوائم</button>';
    drawer.insertBefore(bar,drawer.firstChild);
    var closeBtn=bar.querySelector('[data-hp-close]');
    if(closeBtn) closeBtn.onclick=function(){closeDrawer(id)};
    var homeBtn=bar.querySelector('[data-hp-home]');
    if(homeBtn) homeBtn.onclick=function(){closeDrawer(id)};
  }
  var oldOpen=typeof openDrawer==='function'?openDrawer:null;
  window.openDrawer=function(id){
    if(oldOpen) oldOpen(id);
    else {var el=document.getElementById(id); if(el) el.classList.add('open');}
    setTimeout(function(){hpEnsureBackBar(id)},0);
  };
  var oldClose=typeof closeDrawer==='function'?closeDrawer:null;
  window.closeDrawer=function(id){
    if(oldClose) oldClose(id);
    else {var el=document.getElementById(id); if(el) el.classList.remove('open');}
  };
})();


/* ===== PWA OFFLINE + GITHUB PAGES BRIDGE V10 =====
   Works when the app is hosted outside Apps Script. It opens from local cache,
   saves edits locally, then syncs the whole database to the Apps Script backend
   when internet is available. */
(function(){
  'use strict';
  if (typeof google !== 'undefined' && google.script && google.script.run) return;

  var HP_LOCAL_KEY='hayder_bags_app';
  var HP_PWA_META_KEY='hayder_pack_pwa_meta_v10';
  var HP_PWA_PENDING_KEY='hayder_pack_pwa_pending_v10';
  var HP_PWA_BACKEND_KEY='hayder_pack_backend_url_v10';
  var HP_PWA_SYNC_TIMER=null;
  var HP_PWA_CHECK_TIMER=null;
  var hpPwaRevision=0;
  var hpPwaUpdatedAt='';
  var hpPwaSaving=false;

  function hpPwaClone(v){return JSON.parse(JSON.stringify(v||{}));}
  function hpPwaNormalizeBackendUrl(url){
    url=String(url||'').trim().replace(/\s+/g,'');
    if(!url)return '';
    url=url.replace(/[?#].*$/,'').replace(/\/+$/,'');
    var m=url.match(/^(https:\/\/script\.google\.com\/macros\/s\/[^\/]+)(?:\/(exec|dev))?$/);
    if(m)return m[1]+'/exec';
    return url;
  }
  function hpPwaBackendUrl(){
    var u='';
    try{u=String(localStorage.getItem(HP_PWA_BACKEND_KEY)||'').trim();}catch(e){}
    if(!u && typeof window.HP_APPS_SCRIPT_URL==='string') u=String(window.HP_APPS_SCRIPT_URL||'').trim();
    return hpPwaNormalizeBackendUrl(u);
  }
  function hpPwaSetBackendUrl(url){
    url=hpPwaNormalizeBackendUrl(url);
    if(url && !/^https:\/\/script\.google\.com\/macros\/s\/[^\/]+\/exec$/.test(url)){toast('رابط المزامنة غير صحيح. انسخ رابط Web app اللي آخره /exec');return false;}
    try{localStorage.setItem(HP_PWA_BACKEND_KEY,url);}catch(e){}
    if(typeof window.HP_APPS_SCRIPT_URL!=='undefined') window.HP_APPS_SCRIPT_URL=url;
    toast(url?'تم حفظ رابط المزامنة':'تم مسح رابط المزامنة');
    hpPwaUpdateUi();
    if(url && navigator.onLine) hpPwaPull(true);
    return true;
  }
  function hpPwaFmtTime(v){if(!v)return 'لا توجد بعد';try{return new Date(v).toLocaleString('ar-EG')}catch(e){return String(v)}}
  function hpPwaText(id,text,cls){var el=document.getElementById(id);if(!el)return;el.textContent=text;if(cls)el.className='cloud-status-value '+cls;}
  function hpPwaShowNotice(msg){
    var off=document.getElementById('cloud-offline-banner');
    if(!off)return;
    off.textContent=msg||'لا يوجد اتصال بالإنترنت — التعديل محفوظ مؤقتًا على هذا الجهاز ولم يصل إلى Google بعد.';
    off.classList.add('show');
    clearTimeout(window.__hpPwaNoticeTimer);
    window.__hpPwaNoticeTimer=setTimeout(function(){off.classList.remove('show')},3600);
  }
  function hpPwaSetState(state,msg){
    if(typeof setSyncState==='function') setSyncState(state,msg||'');
    var s=document.getElementById('sync-status'); if(s) s.textContent=msg||'';
    hpPwaText('cloud-connection-status',state==='ok'?'متصل ومحفوظ':state==='work'?'جاري المزامنة':state==='err'?'غير متزامن':'جاهز للعمل أوفلاين',state==='ok'?'success':state==='err'?'danger':state==='work'?'warn':'');
    if(state==='err') hpPwaShowNotice(msg||'التعديل محفوظ مؤقتًا على الجهاز ولم يصل إلى Google بعد.');
  }
  function hpPwaUpdateUi(){
    try{var m=JSON.parse(localStorage.getItem(HP_PWA_META_KEY)||'{}');hpPwaRevision=Number(m.revision)||hpPwaRevision;hpPwaUpdatedAt=m.updatedAt||hpPwaUpdatedAt;}catch(e){}
    hpPwaText('cloud-last-status',hpPwaFmtTime(hpPwaUpdatedAt));
    hpPwaText('cloud-revision-status',String(hpPwaRevision||0));
    var health=document.getElementById('data-health-status');
    if(health && typeof runDataHealthCheckUI==='function') runDataHealthCheckUI();
    var input=document.getElementById('pwa-backend-url'); if(input) input.value=hpPwaBackendUrl();
  }
  function hpPwaHideLoading(){var c=document.getElementById('cloud-loading-cover');if(c)c.classList.add('hide')}
  function hpPwaLoading(t){var e=document.getElementById('cloud-loading-text');if(e)e.textContent=t||'جاري فتح Haydar Pack...'}
  function hpPwaDataForServer(){var copy=hpPwaClone(DB);copy.settings=copy.settings||{};delete copy.settings.dataSafety;delete copy.settings.googleClientId;copy.settings.autoSync=false;return copy;}
  function hpPwaApplyData(data,meta){
    if(!data||typeof data!=='object') throw new Error('الداتا القادمة من Google غير صالحة');
    DB=hpPwaClone(data);
    if(typeof migrate==='function') migrate();
    if(typeof reduceDBForStorage==='function') reduceDBForStorage();
    try{localStorage.setItem(HP_LOCAL_KEY,JSON.stringify(DB));}catch(e){console.warn(e)}
    hpPwaRevision=Number(meta&&meta.revision)||0; hpPwaUpdatedAt=(meta&&meta.updatedAt)||'';
    try{localStorage.setItem(HP_PWA_META_KEY,JSON.stringify({revision:hpPwaRevision,updatedAt:hpPwaUpdatedAt}))}catch(e){}
    if(typeof refreshAll==='function') refreshAll();
    hpPwaUpdateUi();
  }
  function hpPwaJsonp(action, params, timeoutMs){
    return new Promise(function(resolve,reject){
      var url=hpPwaBackendUrl();
      if(!url){reject(new Error('لم يتم ضبط رابط المزامنة'));return;}
      var cb='hpJsonp_'+Date.now()+'_'+Math.floor(Math.random()*100000);
      var q='action='+encodeURIComponent(action)+'&callback='+encodeURIComponent(cb)+'&_='+(Date.now());
      params=params||{};
      Object.keys(params).forEach(function(k){q+='&'+encodeURIComponent(k)+'='+encodeURIComponent(params[k]);});
      var script=document.createElement('script');
      var done=false;
      window[cb]=function(res){done=true;cleanup();resolve(res)};
      function cleanup(){try{delete window[cb]}catch(e){window[cb]=undefined} if(script&&script.parentNode)script.parentNode.removeChild(script); clearTimeout(timer);}
      script.onerror=function(){if(!done){cleanup();reject(new Error('تعذر الاتصال برابط المزامنة'))}};
      var timer=setTimeout(function(){if(!done){cleanup();reject(new Error('لم يصل رد من Apps Script. حدّث ملف Code.gs في Apps Script ثم اعمل Deploy New version، وتأكد أن الرابط ينتهي بـ /exec'))}},timeoutMs||20000);
      script.src=url+(url.indexOf('?')>=0?'&':'?')+q;
      document.head.appendChild(script);
    });
  }
  function hpPwaPost(action, fields){
    return new Promise(function(resolve){
      var url=hpPwaBackendUrl();
      var iframeName='hp_post_'+Date.now();
      var iframe=document.createElement('iframe'); iframe.name=iframeName; iframe.style.display='none';
      var form=document.createElement('form'); form.method='POST'; form.action=url; form.target=iframeName; form.style.display='none';
      fields=fields||{}; fields.action=action;
      Object.keys(fields).forEach(function(k){var inp=document.createElement('input'); inp.type='hidden'; inp.name=k; inp.value=String(fields[k]==null?'':fields[k]); form.appendChild(inp);});
      document.body.appendChild(iframe); document.body.appendChild(form);
      form.submit();
      setTimeout(function(){try{form.remove();iframe.remove();}catch(e){} resolve({ok:true});},1800);
    });
  }
  function hpPwaSaveLocalOnly(){
    try{if(typeof reduceDBForStorage==='function') reduceDBForStorage(); localStorage.setItem(HP_LOCAL_KEY,JSON.stringify(DB));}
    catch(e){toast('تعذر الحفظ المحلي: مساحة الجهاز ممتلئة غالبًا'); return false;}
    try{localStorage.setItem(HP_PWA_PENDING_KEY,JSON.stringify({at:new Date().toISOString(),revision:hpPwaRevision,data:hpPwaDataForServer()}));}catch(e){}
    return true;
  }
  function hpPwaScheduleSync(){clearTimeout(HP_PWA_SYNC_TIMER); HP_PWA_SYNC_TIMER=setTimeout(hpPwaFlush,700);}
  function hpPwaFlush(){
    if(hpPwaSaving) return;
    if(!navigator.onLine){hpPwaSetState('err','أوفلاين — التعديل محفوظ على الجهاز وسيترفع عند رجوع النت');return;}
    if(!hpPwaBackendUrl()){hpPwaSetState('err','اضبط رابط المزامنة مرة واحدة من زر الحفظ السحابي');return;}
    var pending=null; try{pending=JSON.parse(localStorage.getItem(HP_PWA_PENDING_KEY)||'null')}catch(e){}
    if(!pending){hpPwaCheckMeta();return;}
    hpPwaSaving=true; hpPwaSetState('work','جاري رفع التعديلات إلى Google...');
    hpPwaPost('save',{baseRevision:pending.revision||hpPwaRevision,data:JSON.stringify(pending.data||hpPwaDataForServer()),clientTime:new Date().toISOString()}).then(function(){
      setTimeout(function(){
        hpPwaJsonp('data',{},30000).then(function(res){
          hpPwaSaving=false;
          if(res&&res.ok){
            if(Number(res.revision)>hpPwaRevision){localStorage.removeItem(HP_PWA_PENDING_KEY);hpPwaApplyData(res.data,res);hpPwaSetState('ok','تم رفع آخر تعديل على Google');toast('تم رفع التعديلات على Google')}
            else{hpPwaSetState('err','لم يتم تأكيد الرفع بعد. اضغط تحديث/مزامنة عند رجوع النت');}
          }else{hpPwaSetState('err',(res&&res.message)||'فشل تحميل تأكيد الحفظ')}
        }).catch(function(err){hpPwaSaving=false;hpPwaSetState('err',err.message||'تعذر تأكيد الحفظ')});
      },1200);
    });
  }
  function hpPwaPull(showToast){
    if(!navigator.onLine){hpPwaSetState('err','أوفلاين — تم فتح آخر نسخة محفوظة على الجهاز');return;}
    if(!hpPwaBackendUrl()){hpPwaSetState('err','اضبط رابط المزامنة مرة واحدة من زر الحفظ السحابي');return;}
    hpPwaSetState('work','جاري تحميل آخر نسخة من Google...');
    hpPwaJsonp('data',{},30000).then(function(res){
      if(res&&res.ok){hpPwaApplyData(res.data,res);hpPwaSetState('ok','تم تحميل آخر نسخة من Google');if(showToast)toast('تم تحميل آخر تحديث')}
      else hpPwaSetState('err',(res&&res.message)||'تعذر قراءة قاعدة Google');
    }).catch(function(err){hpPwaSetState('err',err.message||'تعذر الاتصال بقاعدة Google')});
  }
  function hpPwaCheckMeta(){
    if(!navigator.onLine||!hpPwaBackendUrl()||document.hidden) return;
    hpPwaJsonp('meta',{},15000).then(function(meta){if(meta&&meta.ok&&Number(meta.revision)>hpPwaRevision&&!localStorage.getItem(HP_PWA_PENDING_KEY))hpPwaPull(false);}).catch(function(){});
  }

  var baseOpenSync=window.openSync;
  window.openSync=function(){
    if(baseOpenSync) baseOpenSync();
    setTimeout(function(){
      var box=document.getElementById('pwa-backend-box');
      if(!box){
        var drawer=document.querySelector('#dr-sync .drawer');
        if(drawer){
          var div=document.createElement('div'); div.id='pwa-backend-box'; div.className='field';
          div.innerHTML='<label>رابط المزامنة Apps Script /exec</label><input id="pwa-backend-url" dir="ltr" placeholder="ضع رابط /exec هنا"><button class="btn blue full" type="button" onclick="savePwaBackendUrlFromInput()"><i class="ti ti-device-floppy"></i> حفظ رابط المزامنة</button>';
          var first=drawer.querySelector('.cloud-status-grid'); drawer.insertBefore(div, first||drawer.children[2]||null);
        }
      }
      hpPwaUpdateUi();
    },0);
  };
  window.savePwaBackendUrlFromInput=function(){var i=document.getElementById('pwa-backend-url'); hpPwaSetBackendUrl(i?i.value:'')};
  window.refreshCloudData=function(show){hpPwaPull(show)};
  window.createCloudBackup=function(){
    if(!hpPwaBackendUrl()||!navigator.onLine){toast('لازم إنترنت ورابط مزامنة');return;}
    hpPwaSetState('work','جاري إنشاء نسخة احتياطية...');
    hpPwaJsonp('backup',{},30000).then(function(res){if(res&&res.ok){hpPwaSetState('ok','تم إنشاء النسخة الاحتياطية');toast('تم إنشاء نسخة احتياطية')}else hpPwaSetState('err',(res&&res.message)||'تعذر إنشاء النسخة')}).catch(function(e){hpPwaSetState('err',e.message)});
  };
  window.loadFromDrive=function(){hpPwaPull(true)};
  window.manualSync=function(){hpPwaFlush()};
  window.scheduleSync=hpPwaScheduleSync;

  save=function(){
    var ok=hpPwaSaveLocalOnly();
    if(ok){hpPwaSetState(navigator.onLine?'work':'err',navigator.onLine?'تم الحفظ على الجهاز وجاري الرفع':'أوفلاين — تم الحفظ على الجهاز'); hpPwaScheduleSync();}
    return ok;
  };

  window.hpCloudBoot=function(){
    hpPwaLoading('جاري فتح Haydar Pack من ذاكرة الجهاز...');
    try{load();}catch(e){console.error(e)}
    hpPwaHideLoading();
    hpPwaUpdateUi();
    var hasLocal=false; try{hasLocal=!!localStorage.getItem(HP_LOCAL_KEY)}catch(e){}
    if(!navigator.onLine){hpPwaSetState('err',hasLocal?'أوفلاين — تم فتح آخر نسخة محفوظة على الجهاز':'أوفلاين — افتح البرنامج أونلاين مرة واحدة أولاً');return;}
    if(hpPwaBackendUrl()) hpPwaPull(false); else hpPwaSetState('err','اضبط رابط المزامنة مرة واحدة من زر الحفظ السحابي');
    clearInterval(HP_PWA_CHECK_TIMER); HP_PWA_CHECK_TIMER=setInterval(hpPwaCheckMeta,30000);
  };
  /* V37: legacy PWA auto-sync listeners are disabled. Auto Local-First Sync is loaded from 12-sync-import.js. */
})();


